import AsyncStorage from '@react-native-async-storage/async-storage';
import NetInfo from '@react-native-community/netinfo';

// Token Generator Utility
const TokenGenerator = {
  generateRandomString(length) {
    const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789';
    let result = '';
    for (let i = 0; i < length; i++) {
      result += chars.charAt(Math.floor(Math.random() * chars.length));
    }
    return result;
  },

  generateToken() {
    const timestamp = Date.now().toString(36);
    const randomPart1 = this.generateRandomString(8);
    const randomPart2 = this.generateRandomString(8);
    const randomPart3 = this.generateRandomString(4);
    const platformPrefix = Platform.OS === 'ios' ? 'iOS' : 'AND';
    return `${platformPrefix}-${timestamp}-${randomPart1}-${randomPart2}-${randomPart3}`;
  },

  generateSessionToken() {
    const sessionId = this.generateRandomString(16);
    const token = this.generateToken();
    return {
      id: `session_${Date.now()}_${Math.floor(Math.random() * 10000)}`,
      sessionId,
      token,
      createdAt: new Date().toISOString(),
      expiresAt: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString(), // 24 hours
      platform: Platform.OS,
      status: 'active',
      actions: [],
      synced: false,
    };
  },

  isTokenExpired(token) {
    return new Date(token.expiresAt) < new Date();
  },

  generateActionToken(actionType, payload = {}) {
    return {
      actionId: `act_${Date.now()}_${Math.floor(Math.random() * 100000)}`,
      actionToken: this.generateToken(),
      actionType,
      payload,
      timestamp: new Date().toISOString(),
      synced: false,
    };
  },
};

// Storage Manager for persisting tokens
const StorageManager = {
  KEYS: {
    SESSIONS: '@offline_sessions',
    ACTIVE_SESSION: '@active_session',
    PENDING_SYNC: '@pending_sync_queue',
  },

  async saveSessions(sessions) {
    try {
      await AsyncStorage.setItem(this.KEYS.SESSIONS, JSON.stringify(sessions));
    } catch (error) {
      console.error('Failed to save sessions:', error);
    }
  },

  async loadSessions() {
    try {
      const data = await AsyncStorage.getItem(this.KEYS.SESSIONS);
      return data ? JSON.parse(data) : [];
    } catch (error) {
      console.error('Failed to load sessions:', error);
      return [];
    }
  },

  async saveActiveSession(session) {
    try {
      await AsyncStorage.setItem(this.KEYS.ACTIVE_SESSION, JSON.stringify(session));
    } catch (error) {
      console.error('Failed to save active session:', error);
    }
  },

  async loadActiveSession() {
    try {
      const data = await AsyncStorage.getItem(this.KEYS.ACTIVE_SESSION);
      return data ? JSON.parse(data) : null;
    } catch (error) {
      console.error('Failed to load active session:', error);
      return null;
    }
  },

  async clearActiveSession() {
    try {
      await AsyncStorage.removeItem(this.KEYS.ACTIVE_SESSION);
    } catch (error) {
      console.error('Failed to clear active session:', error);
    }
  },

  async addToPendingSyncQueue(items) {
    try {
      const existing = await this.getPendingSyncQueue();
      const updated = [...existing, ...items];
      await AsyncStorage.setItem(this.KEYS.PENDING_SYNC, JSON.stringify(updated));
    } catch (error) {
      console.error('Failed to add to sync queue:', error);
    }
  },

  async getPendingSyncQueue() {
    try {
      const data = await AsyncStorage.getItem(this.KEYS.PENDING_SYNC);
      return data ? JSON.parse(data) : [];
    } catch (error) {
      console.error('Failed to get sync queue:', error);
      return [];
    }
  },

  async clearPendingSyncQueue() {
    try {
      await AsyncStorage.removeItem(this.KEYS.PENDING_SYNC);
    } catch (error) {
      console.error('Failed to clear sync queue:', error);
    }
  },

  async clearAll() {
    try {
      await AsyncStorage.multiRemove([
        this.KEYS.SESSIONS,
        this.KEYS.ACTIVE_SESSION,
        this.KEYS.PENDING_SYNC,
      ]);
    } catch (error) {
      console.error('Failed to clear all storage:', error);
    }
  },
};

